export function AccountIcon({
  className,
  iconSrc,
  subtitle,
  width = 128,
  height = 128,
  disabled,
  onClick,
}: AccountIconProps) {
  const buttonClass = [styles.button, disabled ? '' : styles.canClick, className]
    .filter(Boolean)
    .join(' ')

  return (
    <div className={styles.wrapper}>
      <AccountSelectedOutline />
      <button
        className={buttonClass}
        data-test-avatar="win7"
        type="button"
        disabled={disabled}
        onClick={onClick}
      >
        <span className={styles.mask}>
          <Image
            src={
              iconSrc ? '/imgs/windows7/user-icons/user.bmp' : '/imgs/windows7/user-icons/user.bmp'
            }
            alt="User avatar"
            className={styles.image}
            width={width}
            height={height}
            unoptimized
          />
        </span>
      </button>

      {subtitle !== undefined && <span className={styles.subtitle}>{subtitle}</span>}
    </div>
  )
}
